// Helpers
export const TAXONOMY_STATS = {"commerce_types": 20, "categories": 112, "subcategories": 393, "sample_items": 1281};

// Toutes les catégories à plat
export const ALL_CATEGORIES: Category[] = TAXONOMY.flatMap(ct => ct.categories);

// Toutes les sous-catégories à plat
export const ALL_SUBCATEGORIES: SubCategory[] = ALL_CATEGORIES.flatMap(c => c.subcategories);

// Catégories par commerce type
export function getCategoriesByCommerceType(commerceSlug: string): Category[] {
  return TAXONOMY.find(ct => ct.slug === commerceSlug)?.categories || [];
}

// Sous-catégories par catégorie
export function getSubcategoriesByCategory(categoryId: string): SubCategory[] {
  return ALL_CATEGORIES.find(c => c.id === categoryId)?.subcategories || [];
}

// Recherche full-text
export function searchTaxonomy(query: string): Category[] {
  const q = query.toLowerCase().trim();
  if (!q) return [];
  return ALL_CATEGORIES.filter(c =>
    c.name.toLowerCase().includes(q) ||
    c.search_keywords.some(k => k.includes(q))
  );
}